hw = {'peak_tflops': 10.0, 'peak_bw_gbps': 500.0}
layer = {'type': 'linear', 'in': 1024, 'out': 1024}
ms = estimate_latency(layer, hw)
assert ms > 0, f'Latency should be positive, got {ms}'

hw = {'peak_tflops': 10.0, 'peak_bw_gbps': 500.0}
layer_small = {'type': 'linear', 'in': 128, 'out': 128}
layer_large = {'type': 'linear', 'in': 1024, 'out': 1024}
ms_small = estimate_latency(layer_small, hw)
ms_large = estimate_latency(layer_large, hw)
assert ms_large > ms_small, 'Larger layer should take longer'

layer = {'type': 'linear', 'in': 512, 'out': 512}
hw_fast = {'peak_tflops': 100.0, 'peak_bw_gbps': 2000.0}
hw_slow = {'peak_tflops': 1.0, 'peak_bw_gbps': 100.0}
assert estimate_latency(layer, hw_fast) < estimate_latency(layer, hw_slow)

hw = {'peak_tflops': 10.0, 'peak_bw_gbps': 500.0}
layer = {'type': 'conv2d', 'in_c': 64, 'out_c': 128, 'k': 3, 'h': 14, 'w': 14}
ms = estimate_latency(layer, hw)
assert ms > 0

hw = {'peak_tflops': 10.0, 'peak_bw_gbps': 500.0}
try:
    estimate_latency({'type': 'rnn', 'in': 10}, hw)
    assert False
except ValueError:
    pass
